revision.text:
/* {{pp|small=y}} */
.tracked {
	float: right;
	clear: right;
	margin: 0 0 1em 1em;
	width: 12em;
	border: 1px solid #72777d;
	border-radius: 2px;
	background-color: var( --background-color-interactive, #EAECF0 );
    color: var( --color-base, #202122 );
	font-size: 85%;
	text-align: center;
	padding: 0.5em;
}

.tracked-url {
	font-weight: bold;
}

.tracked-closure {
	color: black;
	font-weight: bold;
	text-transform: uppercase;
}

.tracked-resolved {
	color: green;
}

